import jsonimport osclass Manager:    def __init__(self, fn: str = "tasks.json"):        self.fn = fn        self.data = self.load()    def load(self) -> dict:        with open(self.fn, 'r', encoding='utf-8') as f:            return json.load(f)    def save(self):        with open(self.fn, 'w', encoding='utf-8') as f:            json.dump(self.data, f, ensure_ascii=False, indent=2)    def create_tag(self):        t = input("Название тега: ").strip()        self.data["tags"][t] = {"subtags": {}}        self.save()        print(f"Тег {t} создан!")    def create_subtag(self):        print("Доступные теги:")        tags = list(self.data["tags"].keys())        for i, tag in enumerate(tags, 1):            print(f"{i}. {tag}")        choice = int(input("Выберите номер тега: ").strip())        t = tags[choice - 1]        st = input("Название подтега: ").strip()        self.data["tags"][t]["subtags"][st] = {"tasks": []}        self.save()        print(f"Подтег '{st}' создан в '{t}'!")    def add_task(self):        name = input("Название: ").strip()        url = input("Ссылка: ").strip()        rate = int(input("Рейтинг: ").strip())        print("\nДоступные теги:")        tags = list(self.data["tags"].keys())        for i, tag in enumerate(tags, 1):            print(f"{i}. {tag}")        choice = int(input("\nВыберите номер тега: ").strip())        t = tags[choice - 1]        print(f"\nДоступные подтеги в {t}:")        subtags = list(self.data["tags"][t]["subtags"].keys())        for i, st in enumerate(subtags, 1):            print(f"{i}. {st}")        choice2 = int(input("\nВыберите номер подтега: ").strip())        st = subtags[choice2 - 1]        task = {"name": name, "url": url, "rating": rate}        self.data["tags"][t]["subtags"][st]["tasks"].append(task)        self.save()        print(f"Задача {name} добавлена в {t} -> {st}")    def menu(self):        while True:            print("1. Создать тег")            print("2. Создать подтег")            print("3. Добавить задачу")            print("4. Выход")            c = input().strip()            if c == "1":                self.create_tag()            elif c == "2":                self.create_subtag()            elif c == "3":                self.add_task()            elif c == "4":                breakManager().menu()